const services = [
  {
    badge: "Core Service",
    icon: "👥",
    title: "Recruitment Process Outsourcing",
    description:
      "End-to-end talent acquisition management. We embed into your HR function and own the full hiring lifecycle — from sourcing to onboarding.",
    features: [
      "Full-cycle recruiting",
      "Talent pipeline strategy",
      "ATS management & reporting",
      "Employer brand support",
    ],
    primary: true,
  },
  {
    badge: "Popular",
    icon: "🎧",
    title: "Virtual Assistants",
    description:
      "Pre-vetted, skilled VAs that handle your administrative, research, and operational tasks — freeing your team for high-value work.",
    features: [
      "Executive assistance",
      "Data entry & research",
      "Calendar & inbox management",
      "CRM & operations support",
    ],
    primary: false,
  },
  {
    badge: "New",
    icon: "💻",
    title: "Development",
    description:
      "Custom software, web, and product development delivered by vetted engineers integrated into your team on a sprint-by-sprint basis.",
    features: [
      "Web & mobile development",
      "API integrations",
      "Staff augmentation",
      "QA & testing",
    ],
    primary: false,
  },
];

export default function ServicesGrid() {
  return (
    <section id="services" className="bg-slate-50 py-24">
      <div className="max-w-6xl mx-auto px-8">
        <div className="text-center mb-16">
          <p className="text-xs font-semibold text-teal-500 uppercase tracking-widest mb-3">
            What we do
          </p>
          <h2 className="text-4xl font-extrabold text-slate-900 tracking-tight mb-4">
            Three services.
            <br />
            <span className="italic">One growth engine.</span>
          </h2>
          <p className="text-slate-500 text-lg max-w-xl mx-auto">
            Each service integrates seamlessly with your workflow and scales
            with your ambitions.
          </p>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          {services.map((service) => (
            <div
              key={service.title}
              className={`rounded-2xl p-8 border transition-all hover:-translate-y-1 duration-300 ${
                service.primary
                  ? "bg-slate-900 border-slate-900 text-white"
                  : "bg-white border-slate-100 hover:border-teal-200 hover:shadow-lg"
              }`}
            >
              <span
                className={`inline-block text-xs font-semibold uppercase tracking-widest px-2 py-1 rounded mb-4 ${
                  service.primary
                    ? "bg-white/20 text-white"
                    : "bg-teal-50 text-teal-500"
                }`}
              >
                {service.badge}
              </span>
              <div className="text-3xl mb-4">{service.icon}</div>
              <h3
                className={`font-bold text-lg mb-3 ${service.primary ? "text-white" : "text-slate-900"}`}
              >
                {service.title}
              </h3>
              <p
                className={`text-sm leading-relaxed mb-6 ${service.primary ? "text-slate-300" : "text-slate-500"}`}
              >
                {service.description}
              </p>
              <ul
                className={`border-t pt-4 flex flex-col gap-2 ${service.primary ? "border-white/10" : "border-slate-100"}`}
              >
                {service.features.map((f) => (
                  <li
                    key={f}
                    className={`text-sm flex items-center gap-2 ${service.primary ? "text-slate-300" : "text-slate-600"}`}
                  >
                    <span
                      className={`text-xs font-bold ${service.primary ? "text-teal-400" : "text-teal-500"}`}
                    >
                      →
                    </span>
                    {f}
                  </li>
                ))}
              </ul>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
