const points = [
  {
    number: "01",
    tag: "The Problem",
    title: "Hiring is broken, slow, and expensive",
    description:
      "Most companies waste months going through agencies that don't understand their culture, VAs that aren't properly vetted, and dev teams that disappear after the contract. You end up spending more time managing vendors than running your business.",
    dark: false,
  },
  {
    number: "02",
    tag: "Our Approach",
    title: "We embed into your team, not just your inbox",
    description:
      "Inprava doesn't just send you CVs. We become an extension of your team — learning your culture, your standards, and your goals. Every placement, every VA, every developer we deliver is aligned with how you actually work.",
    dark: true,
  },
  {
    number: "03",
    tag: "The Result",
    title: "Faster hires, better talent, less overhead",
    description:
      "Our clients fill roles 3x faster than the industry average, onboard VAs within 48 hours, and ship product with engineers who hit the ground running. All with transparent pricing and a 30-day replacement guarantee.",
    dark: false,
  },
];

export default function WhyInprava() {
  return (
    <section id="why" className="py-24 bg-white">
      <div className="max-w-6xl mx-auto px-8">
        <div className="text-center mb-16">
          <p className="text-xs font-semibold text-teal-500 uppercase tracking-widest mb-3">
            Why Inprava
          </p>
          <h2 className="text-4xl font-extrabold text-slate-900 tracking-tight mb-4">
            Built for companies that <span className="italic">move fast</span>
          </h2>
        </div>
        <div className="flex flex-col gap-6">
          {points.map((point) => (
            <div
              key={point.number}
              className={`rounded-2xl p-10 flex flex-col md:flex-row gap-8 items-start ${
                point.dark
                  ? "bg-slate-900 text-white"
                  : "bg-slate-50 border border-slate-100"
              }`}
            >
              <div className="flex-shrink-0">
                <span
                  className={`text-5xl font-extrabold ${point.dark ? "text-white/20" : "text-slate-200"}`}
                >
                  {point.number}
                </span>
              </div>
              <div className="flex-1">
                <span
                  className={`inline-block text-xs font-semibold uppercase tracking-widest px-2 py-1 rounded mb-4 ${
                    point.dark
                      ? "bg-white/10 text-teal-400"
                      : "bg-teal-50 text-teal-500"
                  }`}
                >
                  {point.tag}
                </span>
                <h3
                  className={`text-2xl font-extrabold mb-3 ${point.dark ? "text-white" : "text-slate-900"}`}
                >
                  {point.title}
                </h3>
                <p
                  className={`text-base leading-relaxed ${point.dark ? "text-slate-300" : "text-slate-500"}`}
                >
                  {point.description}
                </p>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
